+package edu.stanford.futuredata.macrobase.analysis.summary.ratios;
+
+public class GlobalRatioMetric extends ExplanationMetric {
+    @Override
+    public double calc(
+            double matchedOutlier,
+            double matchedTotal,
+            double outlierCount,
+            double totalCount) {
+        return (matchedOutlier / matchedTotal) / (outlierCount / totalCount);
+    }
+
+    @Override
+    public String name() {
+        return "global ratio";
+    }
+}
diff --git a/lib/src/main/java/edu/stanford/futuredata/macrobase/analysis/summary/ratios/RiskRatioMetric.java b/lib/src/main/java/edu/stanford/futuredata/macrobase/analysis/summary/ratios/RiskRatioMetric.java
